620:     /**
621:      * Do actual reads and writes to sockets.
622:      *
623:      * @param timeout The maximum amount of time to wait (in ms) for responses if there are none immediately,
624:      *                must be non-negative. The actual timeout will be the minimum of timeout, request timeout and
625:      *                metadata timeout
626:      * @param now The current time in milliseconds
627:      * @return The list of responses received
628:      */
629:     @Override
630:     public List<ClientResponse> poll(long timeout, long now) {
631:         ensureActive();
632: 
633:         if (!abortedSends.isEmpty()) {
634:             // If there are aborted sends because of unsupported version exceptions or disconnects,
635:             // handle them immediately without waiting for Selector#poll.
636:             List<ClientResponse> responses = new ArrayList<>();
637:             handleAbortedSends(responses);
638:             completeResponses(responses);
639:             return responses;
640:         }
641: 
642:         long metadataTimeout = metadataUpdater.maybeUpdate(now);
643:         long telemetryTimeout = telemetrySender != null ? telemetrySender.maybeUpdate(now) : Integer.MAX_VALUE;
644:         try {
645:             this.selector.poll(Utils.min(timeout, metadataTimeout, telemetryTimeout, defaultRequestTimeoutMs));
646:         } catch (IOException e) {
647:             log.error("Unexpected error during I/O", e);
648:         }
649: 
650:         // process completed actions
651:         long updatedNow = this.time.milliseconds();
652:         List<ClientResponse> responses = new ArrayList<>();
653:         handleCompletedSends(responses, updatedNow);
654:         handleCompletedReceives(responses, updatedNow);
655:         handleDisconnections(responses, updatedNow);
656:         handleConnections();
657:         handleInitiateApiVersionRequests(updatedNow);
658:         handleTimedOutConnections(responses, updatedNow);
659:         handleTimedOutRequests(responses, updatedNow);
660:         handleRebootstrap(responses, updatedNow);
661:         completeResponses(responses);
662: 
663:         return responses;
664:     }
