573:                 if (discoverBrokerVersions && log.isTraceEnabled())
574:                     log.trace("No version information found when sending {} with correlation id {} to node {}. " +
575:                             "Assuming version {}.", clientRequest.apiKey(), clientRequest.correlationId(), nodeId, version);
576:             } else {
