730:      * e.g "NETWORK_EXCEPTION. Error Message: Disconnected from node 0"
731:      */
732:     private String formatErrMsg(ProduceResponse.PartitionResponse response) {
733:         String errorMessageSuffix = (response.errorMessage == null || response.errorMessage.isEmpty()) ?
734:                 "" : String.format(". Error Message: %s", response.errorMessage);
