754:     private void failBatch(ProducerBatch batch,
755:                            ProduceResponse.PartitionResponse response,
756:                            boolean adjustSequenceNumbers) {
757:         final RuntimeException topLevelException;
758:         if (response.error == Errors.TOPIC_AUTHORIZATION_FAILED)
759:             topLevelException = new TopicAuthorizationException(Collections.singleton(batch.topicPartition.topic()));
760:         else if (response.error == Errors.CLUSTER_AUTHORIZATION_FAILED)
761:             topLevelException = new ClusterAuthorizationException("The producer is not authorized to do idempotent sends");
762:         else
763:             topLevelException = response.error.exception(response.errorMessage);
764: 
765:         if (response.recordErrors == null || response.recordErrors.isEmpty()) {
766:             failBatch(batch, topLevelException, adjustSequenceNumbers);
767:         } else {
768:             Map<Integer, RuntimeException> recordErrorMap = new HashMap<>(response.recordErrors.size());
769:             for (ProduceResponse.RecordError recordError : response.recordErrors) {
770:                 // The API leaves us with some awkwardness interpreting the errors in the response.
771:                 // We cannot differentiate between different error cases (such as INVALID_TIMESTAMP)
772:                 // from the single error code at the partition level, so instead we use INVALID_RECORD
773:                 // for all failed records and rely on the message to distinguish the cases.
774:                 final String errorMessage;
775:                 if (recordError.message != null) {
776:                     errorMessage = recordError.message;
777:                 } else if (response.errorMessage != null) {
778:                     errorMessage = response.errorMessage;
